+fn enrichment_report_serde_equality() {
+    let observations = vec![
+        obs(
+            "w1",
+            EvidenceSurface::ShippedPath,
+            false,
+            true,
+            true,
+            false,
+            OwnerRouteHint::RuntimeSemantics,
